import {
  Progress as ProgressPrimitive,
  useProgress,
  useProgressContext,
} from '@ark-ui/react/progress';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './ProgressLinear.module.css';

const ProgressLinearRoot = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Root>,
  ComponentProps<typeof ProgressPrimitive.Root>
>(function ProgressLinearRoot({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Root
      ref={ref}
      data-slot="progress-linear-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearRootProvider = forwardRef<
  ComponentRef<typeof ProgressPrimitive.RootProvider>,
  ComponentProps<typeof ProgressPrimitive.RootProvider>
>(function ProgressLinearRootProvider({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.RootProvider
      ref={ref}
      data-slot="progress-linear-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearLabel = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Label>,
  ComponentProps<typeof ProgressPrimitive.Label>
>(function ProgressLinearLabel({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Label
      ref={ref}
      data-slot="progress-linear-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearValueText = forwardRef<
  ComponentRef<typeof ProgressPrimitive.ValueText>,
  ComponentProps<typeof ProgressPrimitive.ValueText>
>(function ProgressLinearValueText({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.ValueText
      ref={ref}
      data-slot="progress-linear-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearTrack = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Track>,
  ComponentProps<typeof ProgressPrimitive.Track>
>(function ProgressLinearTrack({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Track
      ref={ref}
      data-slot="progress-linear-track"
      className={clsx(styles.track, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearRange = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Range>,
  ComponentProps<typeof ProgressPrimitive.Range>
>(function ProgressLinearRange({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Range
      ref={ref}
      data-slot="progress-linear-range"
      className={clsx(styles.range, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinearView = forwardRef<
  ComponentRef<typeof ProgressPrimitive.View>,
  ComponentProps<typeof ProgressPrimitive.View>
>(function ProgressLinearView({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.View
      ref={ref}
      data-slot="progress-linear-view"
      className={clsx(styles.view, normalizeClassName(className))}
      {...props}
    />
  );
});

const ProgressLinear = Object.assign(ProgressLinearRoot, {
  Root: ProgressLinearRoot,
  RootProvider: ProgressLinearRootProvider,
  Context: ProgressPrimitive.Context,
  Label: ProgressLinearLabel,
  ValueText: ProgressLinearValueText,
  Track: ProgressLinearTrack,
  Range: ProgressLinearRange,
  View: ProgressLinearView,
  useProgress,
  useProgressContext,
});

export { ProgressLinear };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: var(--moduix-progress-linear-gap, var(--moduix-spacing-2));
    width: var(--moduix-progress-linear-width, 12rem);
    color: var(--moduix-progress-linear-color, var(--moduix-color-foreground));

    &[data-orientation='vertical'] {
      grid-template-columns: minmax(0, 1fr) auto;
      grid-template-rows: auto minmax(0, 1fr);
      width: var(--moduix-progress-linear-vertical-width, max-content);
      height: var(--moduix-progress-linear-height, 12rem);
    }
  }

  .label {
    font-size: var(--moduix-progress-linear-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-progress-linear-label-font-weight, var(--moduix-weight-regular));
    line-height: var(--moduix-progress-linear-label-line-height, var(--moduix-line-height-text-sm));
    color: var(--moduix-progress-linear-label-color, currentColor);
  }

  .valueText {
    font-size: var(--moduix-progress-linear-value-text-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-progress-linear-value-text-font-weight, var(--moduix-weight-regular));
    line-height: var(
      --moduix-progress-linear-value-text-line-height,
      var(--moduix-line-height-text-sm)
    );
    justify-self: end;
    color: var(--moduix-progress-linear-value-text-color, currentColor);
    text-align: right;
  }

  .track {
    grid-column: 1 / -1;
    display: block;
    overflow: hidden;
    width: 100%;
    height: var(--moduix-progress-linear-track-height, 0.5rem);
    border-radius: var(--moduix-progress-linear-track-radius, var(--moduix-radius-full));
    background-color: var(--moduix-progress-linear-track-bg, var(--moduix-color-muted));
    box-shadow: inset 0 0 0
      var(--moduix-progress-linear-track-border-width, var(--moduix-border-width-sm))
      var(--moduix-progress-linear-track-border-color, var(--moduix-color-border));

    &[data-orientation='vertical'] {
      display: flex;
      align-items: end;
      width: var(--moduix-progress-linear-track-width, 0.5rem);
      height: 100%;
    }
  }

  .range {
    display: block;
    height: 100%;
    border-radius: var(--moduix-progress-linear-range-radius, inherit);
    background-color: var(--moduix-progress-linear-range-bg, var(--moduix-color-primary));
    transition:
      width var(--moduix-progress-linear-range-transition, var(--moduix-transition-default)),
      height var(--moduix-progress-linear-range-transition, var(--moduix-transition-default));

    &[data-state='indeterminate'] {
      width: var(--moduix-progress-linear-range-indeterminate-width, 35%);
      animation: var(
        --moduix-progress-linear-range-indeterminate-animation,
        progress-linear-indeterminate 1.5s ease-in-out infinite
      );
    }

    &[data-orientation='vertical'] {
      width: 100%;
    }

    &[data-state='indeterminate'][data-orientation='vertical'] {
      height: var(--moduix-progress-linear-range-indeterminate-width, 35%);
      animation: var(
        --moduix-progress-linear-range-indeterminate-vertical-animation,
        progress-linear-indeterminate-vertical 1.5s ease-in-out infinite
      );
    }

    @media (prefers-reduced-motion: reduce) {
      &[data-state='indeterminate'] {
        animation: none;
        transform: translate(0, 0);
      }
    }
  }

  .view {
    display: contents;
  }

  @keyframes progress-linear-indeterminate {
    from {
      transform: translateX(-100%);
    }

    to {
      transform: translateX(300%);
    }
  }

  @keyframes progress-linear-indeterminate-vertical {
    from {
      transform: translateY(100%);
    }

    to {
      transform: translateY(-300%);
    }
  }
}
